def getInitialConfig(self) -> None: super().getInitialConfig() self.getAndStoreDeviceProp("CameraXSize", "CCD_INFO.CCD_MAX_X") self.getAndStoreDeviceProp("CameraYSize", "CCD_INFO.CCD_MAX_Y") self.getAndStoreDeviceProp("CanFastReadout", "CAN_FAST") self.getAndStoreDeviceProp("CanAbortExposure", "CAN_ABORT") self.getAndStoreDeviceProp("CanSetCCDTemperature", "CAN_SET_CCD_TEMPERATURE") self.getAndStoreDeviceProp("CanGetCoolerPower", "CAN_GET_COOLER_POWER") self.getAndStoreDeviceProp("PixelSizeX", "CCD_INFO.CCD_PIXEL_SIZE_X") self.getAndStoreDeviceProp("PixelSizeY", "CCD_INFO.CCD_PIXEL_SIZE_Y") self.getAndStoreDeviceProp("MaxBinX", "CCD_BINNING.HOR_BIN_MAX") self.getAndStoreDeviceProp("MaxBinY", "CCD_BINNING.VERT_BIN_MAX") self.getAndStoreDeviceProp("GainMax", "CCD_GAIN.GAIN_MAX") self.getAndStoreDeviceProp("GainMin", "CCD_GAIN.GAIN_MIN") self.getAndStoreDeviceProp("Gains", "CCD_GAIN.GAIN_LIST") self.getAndStoreDeviceProp("OffsetMax", "CCD_OFFSET.OFFSET_MAX") self.getAndStoreDeviceProp("OffsetMin", "CCD_OFFSET.OFFSET_MIN") self.getAndStoreDeviceProp("Offsets", "CCD_OFFSET.OFFSET_LIST") self.getAndStoreDeviceProp("StartX", "CCD_FRAME.X") self.getAndStoreDeviceProp("StartY", "CCD_FRAME.Y") self.log.debug(f"Initial data: {self.data}")
def saveImage(self): if not self.parent.exposing: print("no exposure") return state = self.getDeviceProp("ImageReady") print(state, self.data["CAMERA.STATE"]) if not state: timeLeft = 1 text = f"expose {timeLeft:3.0f} s" self.signals.message.emit(text) return print("weiter") self.signals.exposed.emit(self.parent.imagePath) self.signals.message.emit("download") data = self.getDeviceProp("ImageArray") data = np.array(data, dtype=np.uint16).transpose() self.signals.downloaded.emit(self.parent.imagePath) self.signals.message.emit("saving") hdu = fits.PrimaryHDU(data=data) hdu.writeto(self.parent.imagePath, overwrite=True) self.parent.writeImageFitsHeader() self.parent.exposeFinished()
def pollData(self) -> None: self.getAndStoreDeviceProp("BinX", "CCD_BINNING.HOR_BIN") self.getAndStoreDeviceProp("BinY", "CCD_BINNING.VERT_BIN") self.getAndStoreDeviceProp("CameraState", "CAMERA.STATE") self.getAndStoreDeviceProp("Gain", "CCD_GAIN.GAIN") self.getAndStoreDeviceProp("Offset", "CCD_OFFSET.OFFSET") self.getAndStoreDeviceProp("FastReadout", "READOUT_QUALITY.QUALITY_LOW") self.getAndStoreDeviceProp("CCDTemperature", "CCD_TEMPERATURE.CCD_TEMPERATURE_VALUE") self.getAndStoreDeviceProp("CoolerOn", "CCD_COOLER.COOLER_ON") self.getAndStoreDeviceProp("CoolerPower", "CCD_COOLER_POWER.CCD_COOLER_VALUE") self.saveImage()
def sendDownloadMode(self) -> None: if self.data.get("CAN_FAST", False): self.setDevicePropQueued("FastReadout", self.parent.fastReadout)
def expose(self) -> None: self.sendDownloadMode() self.setDevicePropQueued("BinX", self.parent.binning) self.setDevicePropQueued("BinY", self.parent.binning) self.setDevicePropQueued("StartX", self.parent.posXASCOM) self.setDevicePropQueued("StartY", self.parent.posYASCOM) self.setDevicePropQueued("NumX", self.parent.widthASCOM) self.setDevicePropQueued("NumY", self.parent.heightASCOM) self.callDeviceMethodQueued("StartExposure", Duration=self.parent.exposureTime, Light=True)
def abort(self) -> bool: if self.data.get("CAN_ABORT", False): self.callDeviceMethodQueued("StopExposure") return True
