    def fake_get(prop: str) -> Any:
        if prop == "Connected":
            call_count["n"] += 1
            return call_count["n"] >= 3
        return None

    function.getDeviceProp = fake_get
    function.setDeviceProp = mock.MagicMock()
    with mock.patch("time.sleep"):
        suc = function.connectDevice()
    assert suc is True


